/** Convert Notion recs to FoodSpot format for unified display */
export function recsAsFoodSpots(): FoodSpot[] {
  return notionRecs
    .filter((r) => r.category !== "shop" && r.category !== "experience")
    .map((r) => ({
      id: r.id,
      name: r.name,
      description: r.description,
      location: r.location,
      neighborhood: r.neighborhood,
      hours: r.hours,
      legSlug: r.legSlug,
      category: r.category as FoodSpot["category"],
      recSource: r.recSource,
      mapsQuery: r.mapsQuery,
      cuisine: r.cuisine,
    }));
}
